import {useMemo} from 'react';
import {useKitsTheme} from '../Contexts/Theme';

/** Single alias → single React CSSProperties camelCase key */
const CSS_PROP_MAP: Record<string, string> = {
    bg: 'backgroundColor',
    bgColor: 'backgroundColor',
    w: 'width',
    h: 'height',
    minW: 'minWidth',
    maxW: 'maxWidth',
    minH: 'minHeight',
    maxH: 'maxHeight',
    p: 'padding',
    pt: 'paddingTop',
    pr: 'paddingRight',
    pb: 'paddingBottom',
    pl: 'paddingLeft',
    m: 'margin',
    mt: 'marginTop',
    mr: 'marginRight',
    mb: 'marginBottom',
    ml: 'marginLeft',
    fontColor: 'color',
    borderW: 'borderWidth',
    shadow: 'boxShadow',
    flexOrder: 'order',
};

/**
 * Shorthands that expand to multiple CSS properties.
 * React Native equivalents (paddingHorizontal / paddingVertical) are handled here too.
 */
const EXPAND_MAP: Record<string, string[]> = {
    px: ['paddingLeft', 'paddingRight'],
    py: ['paddingTop', 'paddingBottom'],
    mx: ['marginLeft', 'marginRight'],
    my: ['marginTop', 'marginBottom'],
    paddingHorizontal: ['paddingLeft', 'paddingRight'],
    paddingVertical: ['paddingTop', 'paddingBottom'],
    borderX: ['borderLeft', 'borderRight'],
    borderY: ['borderTop', 'borderBottom'],
};

/**
 * Resolves theme tokens in a style object and maps KitsConcerto
 * CSS prop names to standard React CSSProperties keys.
 *
 * Used by components that don't use ResponsiveElement (e.g. PrimeReact form controls)
 * to apply theme.components[name].style as inline styles.
 */
export default function useResolvedStyle(themeStyle: Record<string, any>): React.CSSProperties {
    const {resolveToken} = useKitsTheme();

    return useMemo(() => {
        if (!themeStyle || Object.keys(themeStyle).length === 0) return {};

        const resolved: Record<string, any> = {};
        for (const [key, value] of Object.entries(themeStyle)) {
            const resolvedValue = typeof value === 'string' ? resolveToken(value) : value;

            // Expand multi-property shorthands (px, py, paddingHorizontal, etc.)
            if (key in EXPAND_MAP) {
                for (const cssKey of EXPAND_MAP[key]!) {
                    resolved[cssKey] = resolvedValue;
                }
                continue;
            }

            // Map alias or fall through as-is (camelCase CSSProperties pass through unchanged)
            resolved[CSS_PROP_MAP[key] ?? key] = resolvedValue;
        }
        return resolved as React.CSSProperties;
    }, [themeStyle, resolveToken]);
}
